@fieldwise_init
struct Gcd(BinOp, Copyable, Movable):
    def call(self, a: Int, b: Int) -> Int:
        var x = a
        var y = b
        while y != 0:
            var t = y
            y = x % y
            x = t
        return x

def reduce_pairs[F: BinOp](op: F, init: Int, xs: List[Int]) -> Int:
    var acc = init
    for x in xs:
        acc = op.call(acc, x)
    return acc

