trait LessFn(Copyable, Movable):
    def call(self, a: Int, b: Int) -> Bool:
        ...

@fieldwise_init
struct ByAbs(LessFn, Copyable, Movable):
    def call(self, a: Int, b: Int) -> Bool:
        var aa = a if a >= 0 else -a
        var bb = b if b >= 0 else -b
        return aa < bb

def sort_by[F: LessFn](less: F, v: List[Int]) -> List[Int]:
    var r = v.copy()
    for i in range(len(r)):
        for j in range(i + 1, len(r)):
            if less.call(r[j], r[i]):
                var t = r[i]
                r[i] = r[j]
                r[j] = t
    return r^

