@fieldwise_init
struct AtLeast(PredI, Copyable, Movable):
    var t: Int
    def call(self, x: Int) -> Int:
        if x * x >= self.t:
            return 1
        return 0

def find_boundary[F: PredI](pred: F, lo_in: Int, hi_in: Int) -> Int:
    var lo = lo_in
    var hi = hi_in
    while lo < hi:
        var mid = (lo + hi) // 2
        if pred.call(mid) == 1:
            hi = mid
        else:
            lo = mid + 1
    return lo

